 #include "llvm/Transforms/Utils/LoopUtils.h"
+#include "llvm/IR/Instructions.h"
 #include "llvm/ADT/DenseSet.h"
 #include "llvm/ADT/PriorityWorklist.h"
 #include "llvm/ADT/ScopeExit.h"
@@ -47,6 +48,34 @@
 #include "llvm/Transforms/Utils/ScalarEvolutionExpander.h"

 using namespace llvm;
+
+// Check if the instruction represents a problematic zext pattern that could
+// lead to incorrect exit value computation due to bit width issues.
+static bool isProblematicZExtPattern(Instruction *Inst) {
+  // Check if this is a ZExt instruction
+  if (auto *ZExt = dyn_cast<ZExtInst>(Inst)) {
+    Value *Op = ZExt->getOperand(0);
+    // Check if the operand is an Add instruction
+    if (auto *Add = dyn_cast<BinaryOperator>(Op)) {
+      if (Add->getOpcode() == Instruction::Add) {
+        // Check if the add operands are narrower than the zext result
+        Type *AddTy = Add->getType();
+        Type *ZExtTy = ZExt->getType();
+        if (AddTy->isIntegerTy() && ZExtTy->isIntegerTy()) {
+          unsigned AddBits = AddTy->getIntegerBitWidth();
+          unsigned ZExtBits = ZExtTy->getIntegerBitWidth();
+          // If we're extending from a narrow type (less than 32 bits)
+          // this could be problematic
+          if (AddBits < ZExtBits && AddBits < 32) {
+            return true;
+          }
+        }
+      }
+    }
+  }
+  return false;
+}
+
 using namespace llvm::PatternMatch;

 #define DEBUG_TYPE "loop-utils"
@@ -1597,6 +1626,9 @@ int llvm::rewriteLoopExitValues(Loop *L, LoopInfo *LI, TargetLibraryInfo *TLI,

         // Check that InVal is defined in the loop.
         Instruction *Inst = cast<Instruction>(InVal);
+    // Skip problematic zext patterns that could lead to incorrect exit values
+    if (isProblematicZExtPattern(Inst))
+      continue;
         if (!L->contains(Inst))
           continue;

